PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?person WHERE { wd:Q761383 wdt:P138 ?person. }

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?animal WHERE {
  ?operation wdt:P1963 wd:Q625657 .
  ?operation wdt:P1343 ?animal .
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?character WHERE {
  ?character wdt:P451 wd:Q4205826 .
  ?character wdt:P451 wd:Q4463198 .
  FILTER NOT EXISTS { ?character wdt:P175 ?spouse . }
}

