PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT (COUNT(DISTINCT ?president) AS ?numberOfPresidents) WHERE {
  ?president wdt:P31 wd:Q2064 .
  ?president wdt:P527 wd:Q105824503 .
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
