PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT (AVG(?spouseCount) AS ?averageSpouses) WHERE {
  ?headOfState wdt:P31 wd:Q21514624 .
  {
    SELECT ?headOfState (COUNT(?spouse) AS ?spouseCount) WHERE {
      ?headOfState wdt:P26 ?spouse .
    } GROUP BY ?headOfState
  }
}

